before_code:
module priority_enc_16bit(
  input [15:0] req,
  output [3:0] grant,
  output valid
);
  always @(req[15] or req[14] or req[13]) begin
    if (req[15])
      grant = 4'b1111;
    else if (req[14])
      grant = 4'b1110;
    else if (req[13])
      grant = 4'b1101;
    else
      grant = 4'b0000;
  end
  assign valid = |req;
endmodule

after_code:
module priority_enc_16bit(
  input [15:0] req,
  output [3:0] grant,
  output valid
);
  always @(*) begin
    if (req[15])
      grant = 4'b1111;
    else if (req[14])
      grant = 4'b1110;
    else if (req[13])
      grant = 4'b1101;
    else
      grant = 4'b0000;
  end
  assign valid = |req;
endmodule
